void main() {
  var numbers = [3, 1, 4, 1, 5, 9, 2, 6, 5];

  numbers.sort();
  print('Sorted: $numbers');

  numbers.add(7);
  numbers.removeAt(0);
  print('Modified: $numbers');

  var sliced = numbers.sublist(2, 5);
  print('Sliced: $sliced');

  var doubled = numbers.map((n) => n * 2).toList();
  print('Doubled: $doubled');

  var sum = numbers.reduce((a, b) => a + b);
  print('Sum: $sum');
}
